<?php

// Generated by make_tool. Improved by agent: cross-platform path handling.

$toolDefinition_notes_store = array (
  'type' => 'function',
  'function' => 
  array (
    'name' => 'notes_store',
    'description' => 'Store a named note in the agent\'s workspace. Notes persist between sessions and can be recalled or listed. Each note stores a string value by key.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
        'key' => 
        array (
          'type' => 'string',
          'description' => 'Unique key/name for the note',
        ),
        'value' => 
        array (
          'type' => 'string',
          'description' => 'The content of the note to store',
        ),
      ),
      'required' => 
      array (
        0 => 'key',
        1 => 'value',
      ),
    ),
  ),
);

if (! function_exists('notes_store')) {
    function notes_store($key, $value)
    {
        // Normalize key: forward slashes only, no leading/trailing slashes
        $key = trim(str_replace('\\', '/', $key), '/');
        if (!preg_match('/^[a-zA-Z0-9_\-\.\/]+$/', $key)) {
            return json_encode(['error' => 'Key must contain only letters, numbers, hyphens, underscores, dots, and forward slashes']);
        }
        if ($key === '') {
            return json_encode(['error' => 'Key cannot be empty']);
        }
        $notesDir = realpath(__DIR__ . '/../../workspace/notes');
        if ($notesDir === false) {
            $notesDir = __DIR__ . '/../../workspace/notes';
            if (!is_dir($notesDir)) {
                mkdir($notesDir, 0755, true);
            }
            $notesDir = realpath($notesDir);
        }
        $filePath = $notesDir . '/' . $key . '.note';
        $dir = dirname($filePath);
        if (!is_dir($dir)) {
            mkdir($dir, 0755, true);
        }
        $bytes = file_put_contents($filePath, $value);
        return json_encode(['key' => $key, 'bytes_written' => $bytes, 'note_path' => 'workspace/notes/' . $key . '.note']);
    }
}
